select pro_user_id as userId, IFNULL(count(id),0)as num from w_user_pro where pro_user_id in
#{item,jdbcType=VARCHAR}
group by pro_user_id

select u.user_id as userId,u.phone,u.email,u.nick_name as name,u.create_time as createTime, IFNULL(sum(c.consumption),0.0)as consumptionTotal, IFNULL(sum(c.commission),0.0)as commissionTotal from w_user_pro as up left join w_user_info as u on u.user_id = up.user_id left join t_commission_detail as c on c.low_user_id = up.user_id where up.pro_user_id = #{userId,jdbcType=VARCHAR}
and (u.phone = #{account,jdbcType=VARCHAR} or u.email = #{account,jdbcType=VARCHAR})
and u.create_time > #{startTime,jdbcType=VARCHAR}
and #{endTime,jdbcType=VARCHAR} > u.create_time
group by up.user_id order by u.create_time desc
